  "architecture": {
    "components": [
      { "name": "Logistics API Service", "responsibility": "Orchestrates shipment quoting, booking, and payment flows by coordinating external APIs", "boundaries": "Inbound HTTP requests, outbound calls to three external services and a database" },
      { "name": "Geocoding Service (External)", "responsibility": "Address validation and coordinate resolution", "boundaries": "Third-party API with its own SLAs and rate limits" },
      { "name": "Carrier Rates API (External)", "responsibility": "Fetches shipping rates from carriers", "boundaries": "Third-party API, likely aggregates multiple carrier backends" },
      { "name": "Payment Gateway (External)", "responsibility": "Processes payments and authorizations", "boundaries": "Third-party API with PCI compliance boundary" },
      { "name": "Database", "responsibility": "Persists shipment, order, and transaction data", "boundaries": "Internal datastore — confirmed normal query times" }
    ],
    "interfaces": [
      { "from": "Logistics API Service", "to": "Geocoding Service", "contract": "HTTP REST — address in, coordinates out", "coupling_type": "runtime-temporal" },
      { "from": "Logistics API Service", "to": "Carrier Rates API", "contract": "HTTP REST — origin/dest/weight in, rate quotes out", "coupling_type": "runtime-temporal" },
      { "from": "Logistics API Service", "to": "Payment Gateway", "contract": "HTTP REST — payment details in, authorization out", "coupling_type": "runtime-temporal" },
      { "from": "Logistics API Service", "to": "Database", "contract": "SQL/ORM queries", "coupling_type": "runtime-temporal" }
    ],
    "data_flow": "Inbound request → (potentially sequential) calls to geocoding → carrier rates → payment gateway → database write → response. If any external call blocks, the entire request duration extends. At 10K req/day (~0.12 rps avg), throughput is low enough that pure load is not the issue — the bottleneck is per-request latency from downstream calls.",
    "patterns_used": [
      { "pattern": "Hypothesis-Driven Diagnosis", "rationale": "Forming and systematically eliminating hypotheses against the observed evidence to converge on root cause" }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Shipment Orchestration", "classification": "core", "aggregates": ["Shipment", "Quote", "Route"] },
      { "name": "Payment Processing", "classification": "supporting", "aggregates": ["Transaction", "PaymentAuthorization"] },
      { "name": "Address Resolution", "classification": "generic", "aggregates": [] }
    ],
    "context_map": [
      { "upstream": "Geocoding Service", "downstream": "Shipment Orchestration", "relationship": "Conformist — service accepts whatever the geocoding provider returns" },
      { "upstream": "Carrier Rates API", "downstream": "Shipment Orchestration", "relationship": "Conformist — dependent on carrier's rate model" },
      { "upstream": "Payment Gateway", "downstream": "Payment Processing", "relationship": "Anti-Corruption Layer recommended — payment model should not leak into core domain" }
    ]
  },

  "trade_offs": [
    { "decision": "Investigate external APIs first vs. internal profiling", "gains": "Evidence strongly points external: gradual degradation, no deployment, normal DB. Highest probability path.", "sacrifices": "Could miss a subtle internal issue like a memory leak or GC pressure", "alternatives_considered": ["Full internal profiling first", "Parallel investigation of all hypotheses"] },
    { "decision": "Add per-dependency latency tracking before deeper investigation", "gains": "Immediately isolates which external call is degrading, low effort, high signal", "sacrifices": "Adds instrumentation overhead, requires a small deployment", "alternatives_considered": ["Rely on existing logs", "Use network packet capture"] }
  ],

  "flexibility_points": [
    { "area": "External API call pattern", "evolution_path": "Move from sequential to parallel external calls where data dependencies allow, add circuit breakers and timeouts" },
    { "area": "Caching layer for geocoding", "evolution_path": "Address-to-coordinate mappings are highly cacheable; adding a cache would eliminate one external dependency for repeated addresses" },
    { "area": "Observability instrumentation", "evolution_path": "Add per-dependency latency histograms to pinpoint current and future degradation sources" }
  ],

  "rigidity_points": [
    { "area": "Synchronous orchestration of three external APIs", "reason": "Each request is blocked by all three external calls completing — a slow dependency directly inflates end-to-end latency with no isolation" },
    { "area": "Lack of per-dependency timeout/circuit-breaker", "reason": "Without timeouts, a degrading external API can hold connections indefinitely, leading to pool exhaustion and cascading slowness" }
  ],

